@startuml
skinparam packageStyle rectangle
skinparam shadowing false
skinparam classAttributeIconSize 0

package "sandbox" {
  package "design" {
    package "template" {

      class "App" as App << (C,#B7D7B7) >>

      class "GeradorPropriedadesCriptografado" as GPC << (C,#B7D7B7) >>
      class "GeradorXMLCompactado" as GXC << (C,#B7D7B7) >>

      abstract class "GeradorArquivo" as GA << (A,#A9D7E6) >>

      App ..> GPC
      App ..> GXC
      App ..> GA

      GPC --|> GA
      GXC --|> GA
    }
  }
}
@enduml
